import{c as n,S as a,j as h,m as i}from"./chunks/framework.8aa1YH_s.js";const s=JSON.parse('{"title":"Hướng dẫn cho Học viên","description":"","frontmatter":{},"headers":[],"relativePath":"hoc-vien/index.md","filePath":"hoc-vien/index.md","lastUpdated":0}'),o={name:"hoc-vien/index.md"};function e(r,t,d,c,l,g){return a(),h("div",null,[...t[0]||(t[0]=[i('<h1 id="huong-dan-cho-hoc-vien" tabindex="-1">Hướng dẫn cho Học viên <a class="header-anchor" href="#huong-dan-cho-hoc-vien" aria-label="Permalink to “Hướng dẫn cho Học viên”">​</a></h1><p>Chào mừng bạn đến với LamSơn Edutech! Trang này tóm tắt <strong>mọi thứ bạn cần biết</strong> từ lúc đăng ký tài khoản đến khi hoàn thành các kỳ thi.</p><h2 id="bat-đau-nhanh-trong-5-phut" tabindex="-1">Bắt đầu nhanh trong 5 phút <a class="header-anchor" href="#bat-đau-nhanh-trong-5-phut" aria-label="Permalink to “Bắt đầu nhanh trong 5 phút”">​</a></h2><ol><li><strong><a href="./dang-ky-dang-nhap">Đăng ký tài khoản</a></strong> bằng số điện thoại / email.</li><li><strong><a href="./mua-khoa-hoc">Tìm khóa học phù hợp</a></strong> với mục tiêu của bạn (HSA, TSA, THPT...).</li><li><strong><a href="./gio-hang-thanh-toan">Mua khóa</a></strong> qua chuyển khoản / VNPay / Momo.</li><li>Vào <strong><a href="./khoa-hoc-cua-toi">Khóa học của tôi</a></strong> để bắt đầu học.</li><li><strong><a href="./kiem-tra-dau-vao">Làm bài kiểm tra đầu vào</a></strong> để biết trình độ hiện tại.</li><li>Học theo lộ trình và <strong><a href="./luyen-tap">làm thi thử</a></strong> để theo dõi tiến bộ.</li></ol><h2 id="theo-muc-tieu-cua-ban" tabindex="-1">Theo mục tiêu của bạn <a class="header-anchor" href="#theo-muc-tieu-cua-ban" aria-label="Permalink to “Theo mục tiêu của bạn”">​</a></h2><table tabindex="0"><thead><tr><th>Bạn đang ôn thi gì?</th><th>Đi tới</th></tr></thead><tbody><tr><td><strong>Đánh giá năng lực (HSA) - ĐHQG Hà Nội</strong></td><td><a href="./thi-dgnl-hsa">Thi ĐGNL (HSA)</a></td></tr><tr><td><strong>Đánh giá tư duy (TSA) - ĐH Bách Khoa</strong></td><td><a href="./thi-dgtd-tsa">Thi ĐGTD (TSA)</a></td></tr><tr><td><strong>Tốt nghiệp THPT</strong></td><td><a href="./thi-tnthpt">Thi thử Tốt nghiệp THPT</a></td></tr><tr><td>Mới bắt đầu, chưa biết trình độ</td><td><a href="./kiem-tra-dau-vao">Kiểm tra đầu vào</a></td></tr><tr><td>Học từng chuyên đề</td><td><a href="./luyen-tap">Luyện tập</a></td></tr><tr><td>Cần tài liệu, sách</td><td><a href="./hoc-lieu">Học liệu, giáo trình</a></td></tr><tr><td>Muốn làm nhiều đề một lúc</td><td><a href="./bo-de-thi">Bộ đề thi</a></td></tr></tbody></table><h2 id="cau-truc-giao-dien-hoc-vien" tabindex="-1">Cấu trúc giao diện học viên <a class="header-anchor" href="#cau-truc-giao-dien-hoc-vien" aria-label="Permalink to “Cấu trúc giao diện học viên”">​</a></h2><p>Sau khi đăng nhập, bạn sẽ thấy:</p><ul><li><strong>Trang chủ</strong> (<code>https://lamsonedutech.vn/home</code> hoặc <code>https://lamsonedutech.vn/luyen-tap/trang-chu</code>): banner, khóa học nổi bật, khuyến mãi.</li><li><strong>Menu trên</strong> (header): Khóa học, Bộ đề, Học liệu, Tài khoản, Giỏ hàng.</li><li><strong>Avatar góc phải</strong> → Tài khoản / Khóa học của tôi / Hóa đơn / Đăng xuất.</li></ul><h2 id="cac-đuong-dan-quan-trong" tabindex="-1">Các đường dẫn quan trọng <a class="header-anchor" href="#cac-đuong-dan-quan-trong" aria-label="Permalink to “Các đường dẫn quan trọng”">​</a></h2><table tabindex="0"><thead><tr><th>Trang</th><th>Đường dẫn</th></tr></thead><tbody><tr><td>Trang chủ</td><td><code>https://lamsonedutech.vn/home</code></td></tr><tr><td>Hồ sơ cá nhân</td><td><code>https://lamsonedutech.vn/luyen-tap/nguoi-dung/profile</code></td></tr><tr><td>Khóa học của tôi</td><td><code>https://lamsonedutech.vn/luyen-tap/nguoi-dung/khoa-hoc</code></td></tr><tr><td>Hóa đơn của tôi</td><td><code>https://lamsonedutech.vn/luyen-tap/nguoi-dung/hoa-don</code></td></tr><tr><td>Giỏ hàng</td><td><code>https://lamsonedutech.vn/luyen-tap/gio-hang/:id</code></td></tr></tbody></table><h2 id="can-ho-tro" tabindex="-1">Cần hỗ trợ? <a class="header-anchor" href="#can-ho-tro" aria-label="Permalink to “Cần hỗ trợ?”">​</a></h2><ul><li>Sử dụng chức năng <strong><a href="./hoi-dap">Hỏi đáp</a></strong> ngay trong khóa học để hỏi giáo viên.</li><li>Liên hệ hotline / Zalo của trung tâm (xem ở footer).</li><li>Xem <a href="/faq">FAQ</a> cho các câu hỏi thường gặp.</li></ul><h2 id="luu-y-quan-trong" tabindex="-1">Lưu ý quan trọng <a class="header-anchor" href="#luu-y-quan-trong" aria-label="Permalink to “Lưu ý quan trọng”">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Khi làm bài thi</p><ul><li>Không tải lại trang khi đang làm bài.</li><li>Không thoát app khi đồng hồ đang chạy.</li><li>Đảm bảo Internet ổn định trước khi vào phòng thi online.</li><li>Bài thi sẽ tự nộp khi hết giờ - hãy phân bổ thời gian hợp lý.</li></ul></div><div class="tip custom-block"><p class="custom-block-title">Đăng nhập đúng cổng</p><p>Học viên đăng nhập tại <code>https://lamsonedutech.vn/auth/hocvien</code>, không phải cổng admin hay giáo viên.</p></div>',16)])])}const p=n(o,[["render",e]]);export{s as __pageData,p as default};
